enum class Direction { NORTH, SOUTH, EAST, WEST }
val d = Direction.NORTH
println(d)

enum class Color { RED, GREEN, BLUE }
val c = Color.GREEN
val msg = when (c) {
    Color.RED   -> "Stop"
    Color.GREEN -> "Go"
    Color.BLUE  -> "Info"
}
println(msg)

enum class Planet(val mass: Double) {
    EARTH(5.97),
    MARS(0.642)
}
println(Planet.MARS.mass)

enum class Size { SMALL, MEDIUM, LARGE }
println(Size.MEDIUM.ordinal)
println(Size.MEDIUM.name)

enum class Status { ACTIVE, INACTIVE, PENDING }
val s = Status.valueOf("ACTIVE")
println(s == Status.ACTIVE)

enum class Coin(val cents: Int) {
    PENNY(1), NICKEL(5), DIME(10);
    fun inDollars(): Double = cents / 100.0
}
println(Coin.DIME.inDollars())

enum class Level { LOW, MEDIUM, HIGH }
println(Level.HIGH.ordinal > Level.LOW.ordinal)
println(Level.MEDIUM.ordinal)

enum class Season { SPRING, SUMMER, AUTUMN, WINTER }
for (s in Season.values()) {
    print("${s.name} ")
}
